/// <summary>
/// main method.
/// </summary>
/// <param name = "args">Arguemnt</param>
public static void main(Args  args)
{
    ETGLedgerAccrualJouralCreatePostController  controller;

    controller = new ETGLedgerAccrualJouralCreatePostController();
    controller.initializeFromArgs(args);

    if (!ETGACFParameters::find().EnableAccrualSchemePostingMonthly)
        throw Error("@ETG_New:ETGLedgerAccrualJouralCreatePostControllerMain");

    controller.startOperation();
}
